import clsx from 'clsx';
import * as React from 'react';
import throttle from 'lodash/throttle';
import { isFunction } from '../../../util';
import { useCssScope } from '../../../config-provider/hooks';
import { useWillUnmount } from '@universe-design/react-utilities';
import getScrollParent from '../trigger/@popperjs/core/lib/dom-utils/getScrollParent';
import composeRefs from '../../../util/composeRefs';
import { useEventCallback } from '../../../hooks';
import type { NativeScrollAreaProps } from './interface';
import './native-scrollarea.less';

export default React.forwardRef<HTMLDivElement, NativeScrollAreaProps>(
  (
    {
      className,
      onScroll,
      onMouseMove,
      onMouseLeave,
      showScrollBars = 'whenScrolling',
      hideTimeout = 1000,
      scrollX = false,
      scrollY = true,
      ...restProps
    },
    ref,
  ) => {
    const cssScope = useCssScope('scrollArea');
    const scrollContainerRef = React.useRef<HTMLDivElement>(null);
    const composedRef = composeRefs(scrollContainerRef, ref);

    /**
     * ================
     *   Visible
     * ================
     */
    const [visible, setVisible] = React.useState(showScrollBars !== 'whenScrolling');
    const hideScrollbarTimerRef = React.useRef<number>();
    const isMouseOver = React.useRef(false);

    const _clearHideScrollbarTimer = React.useCallback(() => {
      if (hideScrollbarTimerRef.current !== undefined) {
        window.clearTimeout(hideScrollbarTimerRef.current);
        hideScrollbarTimerRef.current = undefined;
      }
    }, []);

    // unmount 的时候清除定时器
    useWillUnmount(() => {
      _clearHideScrollbarTimer();
    });

    const showScrollbar = React.useCallback(() => {
      _clearHideScrollbarTimer();
      setVisible(true);
      hideScrollbarTimerRef.current = window.setTimeout(() => {
        setVisible(false);
      }, hideTimeout);
    }, [_clearHideScrollbarTimer, hideTimeout]);

    const handleScroll: React.UIEventHandler<HTMLDivElement> = ev => {
      isFunction(onScroll) && onScroll(ev);
      showScrollbar();
    };

    const mouseMoveHandler = useEventCallback((ev: React.MouseEvent<HTMLDivElement>) => {
      isFunction(onMouseMove) && onMouseMove(ev);
      /**
       * 检查 mouseMove 触发元素的最近滚动父级是否为本 scrollArea
       * 主要避免 ScrollArea 或者 overflow 元素互相嵌套的情况
       */
      const scrollParent = getScrollParent(ev.target as HTMLElement);
      if (scrollContainerRef.current === scrollParent && isMouseOver.current) {
        showScrollbar();
      }
    });
    const handleMouseMove: React.MouseEventHandler<HTMLDivElement> = React.useMemo(() => {
      const Throttle_Time = 200;
      const mouseMouseMoveHandler = throttle(mouseMoveHandler, Throttle_Time);
      return e => {
        isMouseOver.current = true;
        e.persist();
        mouseMouseMoveHandler(e);
      };
    }, [mouseMoveHandler]);

    const handleMouseLeave: React.MouseEventHandler<HTMLDivElement> = ev => {
      isMouseOver.current = false;
      isFunction(onMouseLeave) && onMouseLeave(ev);
      setVisible(false);
    };
    return (
      <div
        ref={composedRef}
        className={clsx(
          className,
          cssScope(),
          !visible && cssScope('-hide-bar'),
          scrollX && cssScope('-x'),
          scrollY && cssScope('-y'),
        )}
        {...(showScrollBars === 'whenScrolling'
          ? {
              onScroll: handleScroll,
              onMouseMove: handleMouseMove,
              onMouseLeave: handleMouseLeave,
            }
          : { onScroll, onMouseMove, onMouseLeave })}
        {...restProps}
      />
    );
  },
);
